import { h, Signal } from '@tu-lang/runtime'

export const frontmatter = new Signal.State({})
export const Page = () => h("div", {}, [h("$static", {}, [], "<article class=\"tu-markdown\"><h1>tu-xing (图形)</h1>\n<p>A Tu-native UI component library — shadcn + baseui style. Tailwind-driven primitives with theme tokens. Source-only package.</p>\n<blockquote>\n<p>Published as <a href=\"https://www.npmjs.com/package/@tu-lang/tu-xing\"><code>@tu-lang/tu-xing</code></a> on npm. Live demo: <a href=\"https://mowtwo.github.io/tu/playground#tu-xing\">Playground → tu-xing</a>.</p>\n</blockquote>\n<h2>What’s in V1</h2>\n<p>Seven primitives:</p>\n<table>\n<thead>\n<tr>\n<th>Component</th>\n<th>Variants / shapes</th>\n<th>Uses</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><code>Button</code></td>\n<td><code>primary</code> / <code>secondary</code> / <code>ghost</code> / <code>danger</code> × <code>sm</code> / <code>md</code> / <code>lg</code></td>\n<td><code>onClick</code>, <code>disabled</code>, <code>children</code></td>\n</tr>\n<tr>\n<td><code>Input</code></td>\n<td><code>sm</code> / <code>md</code> / <code>lg</code></td>\n<td><code>type</code>, <code>placeholder</code>, <code>value</code>, <code>onInput</code>, <code>disabled</code></td>\n</tr>\n<tr>\n<td><code>Card</code></td>\n<td>—</td>\n<td><code>title</code>, <code>description</code>, <code>footer</code> (slot fn), <code>children</code></td>\n</tr>\n<tr>\n<td><code>Badge</code></td>\n<td><code>brand</code> / <code>success</code> / <code>warning</code> / <code>danger</code> / <code>outline</code></td>\n<td><code>children</code></td>\n</tr>\n<tr>\n<td><code>Switch</code></td>\n<td>—</td>\n<td><code>checked</code>, <code>onChange</code></td>\n</tr>\n<tr>\n<td><code>Dialog</code></td>\n<td>—</td>\n<td><code>open</code>, <code>onClose</code>, <code>title</code>, <code>children</code></td>\n</tr>\n<tr>\n<td><code>Tabs</code></td>\n<td>—</td>\n<td><code>items</code>, <code>active</code>, <code>onSelect</code></td>\n</tr>\n</tbody>\n</table>\n<h2>Style philosophy</h2>\n<ul>\n<li><strong>shadcn-like</strong>: every component is a single <code>.tu</code> file. Source-only — consumers import via <code>@tu-lang/vite</code>. Easy to fork into your own project.</li>\n<li><strong>baseui-like</strong>: theme tokens live in <code>theme.css</code> as HSL CSS variables (<code>--tu-brand</code>, <code>--tu-surface</code>, …). Override at the document root to retheme. Light + dark palettes ship by default.</li>\n<li><strong>Tailwind-driven</strong>: every component uses Tailwind utility classes referencing the theme tokens via <code>bg-[hsl(var(--tu-brand))]</code> and friends.</li>\n</ul>\n<h2>Install</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#B392F0\">pnpm</span><span style=\"color:#9ECBFF\"> add</span><span style=\"color:#9ECBFF\"> @tu-lang/tu-xing</span><span style=\"color:#9ECBFF\"> @tu-lang/runtime</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">pnpm</span><span style=\"color:#9ECBFF\"> add</span><span style=\"color:#79B8FF\"> -D</span><span style=\"color:#9ECBFF\"> tailwindcss</span><span style=\"color:#9ECBFF\"> @tailwindcss/vite</span><span style=\"color:#9ECBFF\"> @tu-lang/vite</span></span>\n<span class=\"line\"></span></code></pre>\n<p>In your entry CSS:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">@import</span><span style=\"color:#9ECBFF\"> \"tailwindcss\"</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">@import</span><span style=\"color:#9ECBFF\"> \"@tu-lang/tu-xing/theme.css\"</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">@source</span><span style=\"color:#E1E4E8\"> \"./**/*.tu\";</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">@source</span><span style=\"color:#E1E4E8\"> \"../node_modules/@tu-lang/tu-xing/src\";</span></span>\n<span class=\"line\"></span></code></pre>\n<p>In your Vite config:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> tailwindcss </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@tailwindcss/vite'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> tu </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@tu-lang/vite'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { defineConfig } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> 'vite'</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> default</span><span style=\"color:#B392F0\"> defineConfig</span><span style=\"color:#E1E4E8\">({</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  plugins: [</span><span style=\"color:#B392F0\">tu</span><span style=\"color:#E1E4E8\">(), </span><span style=\"color:#B392F0\">tailwindcss</span><span style=\"color:#E1E4E8\">()],</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">})</span></span>\n<span class=\"line\"></span></code></pre>\n<h2>Use</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Button</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"@tu-lang/tu-xing/Button.tu\"</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Card</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"@tu-lang/tu-xing/Card.tu\"</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Badge</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"@tu-lang/tu-xing/Badge.tu\"</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> let</span><span style=\"color:#B392F0\"> App</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> () </span><span style=\"color:#F97583\">=></span><span style=\"color:#79B8FF\"> Card</span><span style=\"color:#E1E4E8\">(</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">  title</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"Welcome\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">  description</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"Tu × Tailwind × shadcn\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">  footer</span><span style=\"color:#E1E4E8\">: () </span><span style=\"color:#F97583\">=></span><span style=\"color:#79B8FF\"> Button</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">variant</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"primary\"</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"Get started\"</span><span style=\"color:#E1E4E8\"> },</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  p</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#9ECBFF\">    \"Built with Tu's M6.1 named-arg components — props default optional. \"</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">    Badge</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">variant</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"success\"</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"stable\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h2>Theme</h2>\n<p>Override the HSL channels at the document root:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#B392F0\">:root</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#FFAB70\">  --tu-brand</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">280</span><span style=\"color:#79B8FF\"> 90</span><span style=\"color:#F97583\">%</span><span style=\"color:#79B8FF\"> 60</span><span style=\"color:#F97583\">%</span><span style=\"color:#E1E4E8\">;       </span><span style=\"color:#6A737D\">/* purple instead of indigo */</span></span>\n<span class=\"line\"><span style=\"color:#FFAB70\">  --tu-radius</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">;             </span><span style=\"color:#6A737D\">/* rounder corners */</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p>For light mode, set <code>data-theme=&quot;light&quot;</code> on <code>&lt;html&gt;</code> or any parent.</p>\n<h2>Roadmap</h2>\n<ul>\n<li>More primitives (Select, Tooltip, Popover, Toast)</li>\n<li><code>tu add &lt;component&gt;</code> CLI for shadcn-style copy-paste install</li>\n<li>Form helpers (Form, Field, Label) once Tu has param destructuring</li>\n<li>Full WCAG keyboard nav for Tabs / Dialog / Switch</li>\n</ul>\n</article>")])
